// 1. Sadə Type Constraint
function printLength<T extends { length: number }>(item: T): number {
  return item.length;
}
console.log(printLength("Test")); // Çıxış: 4
console.log(printLength([1, 2, 3])); // Çıxış: 3
// console.log(printLength(42)); // Səhv: number-ın length xüsusiyyəti yoxdur

// 2. Interfeysdə Type Constraint
interface Item<T extends string | number> {
  data: T;
}
const stringItem: Item<string> = { data: "Hello" };
const numberItem: Item<number> = { data: 123 };
console.log(stringItem); // Çıxış: { data: "Hello" }
console.log(numberItem); // Çıxış: { data: 123 }
// const boolItem: Item<boolean> = { data: true }; // Səhv: boolean string | number-a uyğun deyil

// 3. Sinifdə Type Constraint
class Store<T extends { id: string }> {
  items: T[] = [];
  add(item: T): void {
    this.items.push(item);
  }
  getById(id: string): T | undefined {
    return this.items.find(item => item.id === id);
  }
}
const productStore = new Store<{ id: string; name: string }>();

  productStore.add({ id: "P001", name: "Laptop" });
console.log(productStore.getById("P001")); // Çıxış: { id: "P001", name: "Laptop" }
// productStore.add({ name: "Mouse" }); // Səhv: id xüsusiyyəti tələb olunur

// 4. Çoxsaylı Type Constraints
function compare<T extends { value: number }, U extends { value: number }>(a: T, b: U): number {
  return a.value - b.value;
}
const obj1 = { value: 10 };
const obj2 = { value: 5 };
console.log(compare(obj1, obj2)); // Çıxış: 5
// console.log(compare({ name: "Test" }, { name: "Test2" })); // Səhv: value xüsusiyyəti tələb olunur

// 5. Union Tipləri ilə Type Constraint
type AllowedType = string | number;
function restrict<T extends AllowedType>(value: T): T {
  return value;
}
console.log(restrict("Hello")); // Çıxış: Hello
console.log(restrict(123)); // Çıxış: 123
// console.log(restrict(true)); // Səhv: boolean AllowedType-a uyğun deyil

// 6. Default Tiplər ilə Type Constraint
class Wrapper<T extends string = string> {
  value: T;
  constructor(value: T) {
    this.value = value;
  }
  getValue(): T {
    return this.value;
  }
}
const defaultWrapper = new Wrapper("Test"); // T avtomatik string olur
const numberWrapper = new Wrapper<string>("Hello");
console.log(defaultWrapper.getValue()); // Çıxış: Test
console.log(numberWrapper.getValue()); // Çıxış: Hello

// 7. Type Constraint ilə funksiyalar və interfeyslər
interface Printable<T extends { toString(): string }> {
  item: T;
  print(): string;
}
class Printer<T extends { toString(): string }> implements Printable<T> {
  item: T;
  constructor(item: T) {
    this.item = item;
  }
  print(): string {
    return this.item.toString();
  }
}
const printer = new Printer<Date>(new Date());
console.log(printer.print()); // Çıxış: Cari tarix və vaxtın sətir formatı

